//! Reusable CLI options and flags (OFs) shared across subcommands.
//!
//! Each shared OF lives in its own submodule as a "leaf" — a
//! `#[derive(Args)]` struct holding the flag(s), value-parser(s),
//! and any helper types. Subcommands opt in by flattening leaves
//! (or composed bundles) into their own `#[derive(Args)]` struct
//! with `#[command(flatten)]`.
//!
//! - **Leaf** — one `#[derive(Args)]` per logical OF (single flag
//!   or a small fixed pair like push-retry). Holds the typed
//!   value, `value_parser`, default, and help text (via the field
//!   doc-comment).
//! - **Bundle** — a `#[derive(Args)]` that flattens N leaves into
//!   a named role (e.g. `ProvisionCommon`). One flatten line at
//!   the consumer picks up the whole bundle.
//! - **Pattern A escape hatch** — when a consumer needs unique
//!   help text for an OF, it skips the leaf's flatten and inlines
//!   its own field with `#[arg(value_parser = …)]`, reusing the
//!   leaf's typed value and parser.
//!
//! Modules:
//!
//! - `config` — `--config none|<path>` (init's `.vc-config.toml`
//!   override; reusable by future commands).

/// Marker trait for OF leaves and bundles.
///
/// Every type defined in `options_flags/` derives `clap::Args` and
/// implements this marker so generic helpers (and a future external
/// crate consumer) can constrain "this is a vc-x1 OF surface".
/// Documentation-level — clap derive doesn't see this trait; the
/// discipline is that every leaf and bundle declares it explicitly.
pub trait FlagBundle: clap::Args {}

/// Canonical shape for a flag's typed value-parser.
///
/// Leaves whose value-parser produces a typed value (rather than
/// using clap's built-in primitive parsers) declare a unit-struct
/// implementor of this trait. The `parse` associated fn matches
/// clap's `value_parser` signature, so consumers wire it up as
/// `#[arg(value_parser = MyParser::parse)]`.
///
/// Documentation-level — clap consumes the function pointer
/// directly; the trait only canonicalizes the shape across leaves.
pub trait FlagParser {
    /// The typed value the parser produces.
    type Value;

    /// Parse a CLI string into the typed value.
    fn parse(s: &str) -> Result<Self::Value, String>;
}

pub mod config;

